SELECT s.selection_id, s.student_id, stu.real_name AS student_name, stu.student_no, s.topic_id, t.topic_name, t.description AS topic_description, s.teacher_id, tea.real_name AS teacher_name, tea.teacher_no, s.campus_name, s.academic_year, s.status, s.apply_reason, s.reject_reason, s.is_custom_topic, s.custom_topic_name, s.custom_topic_description, s.create_time, s.update_time FROM project_selection s LEFT JOIN sys_user stu ON s.student_id = stu.user_id AND stu.is_deleted = 0 LEFT JOIN project_topic t ON s.topic_id = t.topic_id AND t.is_deleted = 0 LEFT JOIN sys_user tea ON s.teacher_id = tea.user_id AND tea.is_deleted = 0 WHERE s.is_deleted = 0
AND s.campus_name LIKE CONCAT('%', #{req.campusName}, '%')
AND s.teacher_id = #{req.teacherId}
AND s.student_id = #{req.studentId}
AND s.academic_year = #{req.academicYear}
AND s.status = #{req.status}
AND (stu.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR stu.student_no LIKE CONCAT('%', #{req.keyword}, '%') OR t.topic_name LIKE CONCAT('%', #{req.keyword}, '%') OR s.custom_topic_name LIKE CONCAT('%', #{req.keyword}, '%'))
ORDER BY s.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(s.selection_id) FROM project_selection s LEFT JOIN sys_user stu ON s.student_id = stu.user_id AND stu.is_deleted = 0 LEFT JOIN project_topic t ON s.topic_id = t.topic_id AND t.is_deleted = 0 WHERE s.is_deleted = 0
AND s.campus_name LIKE CONCAT('%', #{req.campusName}, '%')
AND s.teacher_id = #{req.teacherId}
AND s.student_id = #{req.studentId}
AND s.academic_year = #{req.academicYear}
AND s.status = #{req.status}
AND (stu.real_name LIKE CONCAT('%', #{req.keyword}, '%') OR stu.student_no LIKE CONCAT('%', #{req.keyword}, '%') OR t.topic_name LIKE CONCAT('%', #{req.keyword}, '%') OR s.custom_topic_name LIKE CONCAT('%', #{req.keyword}, '%'))
